import { memo, Suspense, type ReactNode } from 'react'

import { useNavigate } from 'react-router-dom'

import {
  Box,
  Button,
  CircularProgress,
  LinearProgress,
  Typography,
  type BoxProps,
  mergeSlotProps,
} from '@mui/material'

import { routes } from '@/routes'

import type { ContentIdentifier } from '../types'

export type QuizStats = BoxProps & {
  currentIndex: number
  total: number
  passCount: number
  failCount: number
  progress: number
}

export function QuizEmptyState() {
  return (
    <Box sx={{ padding: 4, textAlign: 'center' }}>
      <Typography variant="body2" color="text.secondary">
        학습할 카드가 없습니다.
      </Typography>
    </Box>
  )
}

export function QuizCompleteState({
  className,
  passCount,
  failCount,
  total,
  content,
  onRestart,
}: {
  className?: string
  passCount: number
  failCount: number
  total: number
  content: Partial<ContentIdentifier>
  onRestart: () => void
}) {
  const navigate = useNavigate()
  return (
    <Box
      className={className}
      sx={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
      }}
    >
      <Box
        sx={{
          flexGrow: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        <Typography variant="h5" gutterBottom>
          학습 완료!
        </Typography>
        <Box sx={{ my: 3, textAlign: 'center' }}>
          <Typography variant="h6" color="success.main">
            맞음: {passCount}
          </Typography>
          <Typography variant="h6" color="error.main">
            틀림: {failCount}
          </Typography>
          <Typography variant="body1" sx={{ mt: 2 }}>
            정답률: {total > 0 ? Math.round((passCount / total) * 100) : 0}%
          </Typography>
        </Box>
      </Box>
      <Box sx={{ display: 'flex', gap: 2, mt: 4 }}>
        <Button
          variant="outlined"
          size="large"
          onClick={() => {
            navigate(routes.flashMan.cards.$({ ...content }))
          }}
        >
          카드
        </Button>
        <Button
          variant="outlined"
          size="large"
          onClick={() => {
            navigate(routes.flashMan.learn.$({ ...content }))
          }}
        >
          설정
        </Button>
        <Button variant="contained" size="large" onClick={onRestart}>
          다시하기
        </Button>
      </Box>
    </Box>
  )
}

export function QuizProgressBar({
  currentIndex,
  total,
  passCount,
  failCount,
  progress,
  ...boxProps
}: QuizStats) {
  return (
    <Box {...mergeSlotProps(boxProps, {})}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
        <Typography variant="body2" color="text.secondary">
          {currentIndex + 1} / {total}
        </Typography>
        <Typography variant="body2">
          <Typography component="span" color="success.main">
            {passCount}
          </Typography>
          {' / '}
          <Typography component="span" color="error.main">
            {failCount}
          </Typography>
        </Typography>
      </Box>
      <LinearProgress variant="determinate" value={progress} sx={{ height: 8, borderRadius: 4 }} />
    </Box>
  )
}

function QuizSuspenseWrapperInner({ children }: { children: ReactNode }) {
  return (
    <Suspense
      fallback={
        <Box
          sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '50vh' }}
        >
          <CircularProgress />
        </Box>
      }
    >
      {children}
    </Suspense>
  )
}

export const QuizSuspenseWrapper = memo(QuizSuspenseWrapperInner)
