import { memo, Suspense, useCallback, useMemo } from 'react'

import { useAtom } from 'jotai'
import { useNavigate } from 'react-router-dom'

import CloseIcon from '@mui/icons-material/Close'
import {
  Box,
  Button,
  Checkbox,
  CircularProgress,
  FormControl,
  FormControlLabel,
  FormLabel,
  Grid,
  IconButton,
  InputLabel,
  MenuItem,
  Radio,
  RadioGroup,
  Select,
  Typography,
} from '@mui/material'

import { useTypedSearchParams } from '@/hooks/useTypedSearchParams'
import { routes } from '@/routes'

import {
  learnConfigAtom,
  type Language,
  type LearnConfig,
  type QaDirection,
  type QaType,
} from '../atoms'
import { useGithubCardContextNext } from '../hooks/useFlashCardContent'
import type { ContentIdentifier } from '../types'

import ContentStatus from './ContentStatus'

export type LearnConfigEntryProps = {
  className?: string
  contentId: ContentIdentifier
}

function LearnConfigEntryContent(props: LearnConfigEntryProps) {
  const { className, contentId } = props
  const navigate = useNavigate()
  const [learnConfig, setLearnConfig] = useAtom(learnConfigAtom)

  const {
    shuffle,
    qaDirection,
    qaType,
    hideHint,
    soundOnLearning,
    ttsForQuestion,
    ttsForAnswer,
    ttsLang,
  } = learnConfig

  const { content, contentPrev, contentNext } = useGithubCardContextNext(contentId)

  const flashCardItems = useMemo(() => {
    if (!content?.flashCardItems) return []
    return content.flashCardItems
  }, [content])

  const total = flashCardItems.length

  const handleConfigChange = useCallback(
    (config: Partial<LearnConfig>) => {
      setLearnConfig((prev) => ({ ...prev, ...config }))
    },
    [setLearnConfig]
  )

  const handleStart = useCallback(() => {
    if (qaType === 'one-from-many') {
      navigate(routes.flashMan.learn.oneFromMany.$(contentId))
    } else {
      navigate(routes.flashMan.learn.shortAnswer.$(contentId))
    }
  }, [qaType, navigate, contentId])

  // const handleClose = useCallback(() => {
  //   navigate(routes.flashMan.cards.$(contentId))
  // }, [navigate, contentId])

  // if (!content || total === 0) {
  //   return (
  //     <Box sx={{ padding: 4, textAlign: 'center' }}>
  //       <Typography variant="body2" color="text.secondary">
  //         학습할 카드가 없습니다.
  //       </Typography>
  //       <Button variant="outlined" onClick={handleClose} sx={{ mt: 2 }}>
  //         돌아가기
  //       </Button>
  //     </Box>
  //   )
  // }

  return (
    <Box
      className={className}
      sx={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        padding: 2,
      }}
    >
      {/* Header */}
      <Box sx={{ display: 'flex' }}>
        <Box sx={{ transform: 'translate(-.5rem, -.2rem)' }}>
          <IconButton
            onClick={() => {
              navigate(routes.flashMan.cards.$(contentId))
            }}
          >
            <CloseIcon />
          </IconButton>
        </Box>
        <Box sx={{ flexGrow: 1, mb: 3 }}>
          <Typography variant="h6">{content?.name}</Typography>
          <Typography variant="body2" color="text.secondary">
            총 {total}개의 문제
          </Typography>
        </Box>
      </Box>

      {/* Configuration Form */}
      <Box
        sx={{
          flexGrow: 1,
          display: 'flex',
          flexDirection: 'column',
          gap: 2,
          '& .MuiFormControl-root': {
            width: '100%',
          },
        }}
      >
        <Grid container spacing={2}>
          <Grid size={{ xs: 12 }}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={shuffle}
                  onChange={() => handleConfigChange({ shuffle: !shuffle })}
                />
              }
              label="문제 섞기"
            />
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControl component="fieldset">
              <FormLabel component="legend">질문 정답 바꾸기</FormLabel>
              <RadioGroup
                row
                name="qa-direction"
                value={qaDirection}
                onChange={(e) => handleConfigChange({ qaDirection: e.target.value as QaDirection })}
              >
                <FormControlLabel value="forward" control={<Radio />} label="문제 -> 답" />
                <FormControlLabel value="reverse" control={<Radio />} label="답 -> 문제" />
              </RadioGroup>
            </FormControl>
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControl component="fieldset">
              <FormLabel component="legend">문제 유형</FormLabel>
              <RadioGroup
                row
                name="qa-type"
                value={qaType}
                onChange={(e) => handleConfigChange({ qaType: e.target.value as QaType })}
              >
                <FormControlLabel value="one-from-many" control={<Radio />} label="고르기" />
                <FormControlLabel value="short-answer" control={<Radio />} label="입력하기" />
              </RadioGroup>
            </FormControl>
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={hideHint}
                  onChange={(e) => handleConfigChange({ hideHint: e.target.checked })}
                />
              }
              label="힌트 가리기"
            />
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={soundOnLearning}
                  onChange={(e) => handleConfigChange({ soundOnLearning: e.target.checked })}
                />
              }
              label="효과음"
            />
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={ttsForQuestion}
                  onChange={(e) => handleConfigChange({ ttsForQuestion: e.target.checked })}
                />
              }
              label="문제 말하기"
            />
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControlLabel
              control={
                <Checkbox
                  checked={ttsForAnswer}
                  onChange={(e) => handleConfigChange({ ttsForAnswer: e.target.checked })}
                />
              }
              label="정답 말하기"
            />
          </Grid>

          <Grid size={{ xs: 12 }}>
            <FormControl fullWidth>
              <InputLabel id="tts-lang-label">TTS 언어</InputLabel>
              <Select
                labelId="tts-lang-label"
                value={ttsLang}
                label="TTS 언어"
                onChange={(e) => handleConfigChange({ ttsLang: e.target.value as Language })}
              >
                <MenuItem value="ko-KR">한국어</MenuItem>
                <MenuItem value="en-US">영어</MenuItem>
                <MenuItem value="ja-JP">일본어</MenuItem>
              </Select>
            </FormControl>
          </Grid>
        </Grid>
      </Box>

      {/* Action Buttons */}
      <Box
        sx={({ palette }) => ({
          position: 'sticky',
          bottom: 0,
          display: 'flex',
          gap: 1,
          mt: 2,
          pt: 2,
          borderTop: 1,
          borderColor: 'divider',
          backgroundColor: palette.background.paper,
          justifyContent: 'space-evenly',
        })}
      >
        <Button
          variant="contained"
          size="large"
          onClick={() => {
            navigate(
              routes.flashMan.learn.$({
                owner: contentId.owner,
                repo: contentId.repo,
                path: contentPrev?.path || '',
              })
            )
          }}
          disabled={!contentPrev}
        >
          이전{contentPrev && <ContentStatus simple content={content} />}
        </Button>
        <Button
          variant="contained"
          size="large"
          onClick={handleStart}
          disabled={total === 0}
          // sx={{ flexGrow: 2 }}
        >
          시작 {content && <ContentStatus simple content={content} />}
        </Button>
        <Button
          variant="contained"
          size="large"
          onClick={() => {
            navigate(
              routes.flashMan.learn.$({
                owner: contentId.owner,
                repo: contentId.repo,
                path: contentNext?.path || '',
              })
            )
          }}
          disabled={!contentNext}
        >
          다음{contentNext && <ContentStatus simple content={contentNext} />}
        </Button>
      </Box>
    </Box>
  )
}

function LearnConfigEntry() {
  const { queryParams } = useTypedSearchParams(routes.flashMan.learn.$config)
  const { owner, repo, path } = queryParams
  return (
    <Suspense
      fallback={
        <Box
          sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '50vh' }}
        >
          <CircularProgress />
        </Box>
      }
    >
      {owner && repo && path ? (
        <LearnConfigEntryContent contentId={{ owner, repo, path }} />
      ) : (
        <>
          <Box>Invalid parameters</Box>
        </>
      )}
    </Suspense>
  )
}

export default memo(LearnConfigEntry)
