import { useCallback, useMemo, useState } from 'react'

import { useAtomValue } from 'jotai'

import { learnConfigAtom } from '../atoms'
import { useGithubToken } from '../hooks'
import type { FlashCardItem } from '../types'
import { shuffleArray } from '../utils'

import { useAddHistory } from './useAddHistory'
import { useFlashCardContent } from './useFlashCardContent'

export function useFlashCardQuiz(params: { owner?: string; repo?: string; path?: string }) {
  const { owner, repo, path } = params
  const token = useGithubToken()
  const { shuffle, qaDirection } = useAtomValue(learnConfigAtom)

  const { content } = useFlashCardContent(params)

  const contentInfo = useMemo(() => {
    if (!content || !owner || !repo || !path || !content.sha) return null
    return { owner, repo, path, sha: content.sha }
  }, [content, owner, repo, path])

  const { addResult: addHistoryResult, completeSession } = useAddHistory(contentInfo)

  const [currentIndex, setCurrentIndex] = useState(0)
  const [results, setResults] = useState<Map<number, 'pass' | 'fail'>>(new Map())
  const [isComplete, setIsComplete] = useState(false)

  const contentFlashCardItems = content?.flashCardItems
  const flashCardItems = useMemo<FlashCardItem[]>(() => {
    if (!contentFlashCardItems) return []
    const items =
      qaDirection === 'reverse'
        ? contentFlashCardItems.map((item) => ({ ...item, q: item.a, a: item.q }))
        : contentFlashCardItems
    return shuffle ? shuffleArray(items) : items
  }, [contentFlashCardItems, qaDirection, shuffle])

  const currentItem = flashCardItems[currentIndex]
  const total = flashCardItems.length
  const passCount = Array.from(results.values()).filter((r) => r === 'pass').length
  const failCount = Array.from(results.values()).filter((r) => r === 'fail').length
  const progress = total > 0 ? ((passCount + failCount) / total) * 100 : 0

  const recordResult = useCallback(
    (result: 'pass' | 'fail') => {
      setResults((prev) => new Map(prev).set(currentIndex, result))
      if (currentItem) {
        addHistoryResult(result, currentItem.lineNo)
      }
    },
    [currentIndex, currentItem, addHistoryResult]
  )

  const advance = useCallback(() => {
    if (currentIndex < total - 1) {
      setCurrentIndex((prev) => prev + 1)
    } else {
      setIsComplete(true)
      completeSession()
    }
  }, [currentIndex, total, completeSession])

  const restart = useCallback(() => {
    setCurrentIndex(0)
    setResults(new Map())
    setIsComplete(false)
  }, [])

  return {
    content,
    token,
    flashCardItems,
    currentIndex,
    currentItem,
    total,
    passCount,
    failCount,
    progress,
    isComplete,
    recordResult,
    advance,
    restart,
  }
}
